var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"어휴, 유리 언니. 미용실 좀 자주 가야겠다. 머리 푸석푸석한 것 좀 봐.","JPN":"もう、ユリさんったら。美容室にちょくちょく行った方がいいですよ。髪の毛傷みすぎ。","ENG":"Sheesh, Yuri. You really need to get a haircut. It's all frizzy and unkempt.","TWN":"哎呀，悠麗姊姊，你要常去美容院啦，你看你的頭髮亂七八糟的。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L4_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"그러게 그냥 놔두라고 했잖아. 왜 사서 고생이야?","JPN":"だから放っといてっていってるだろ。なんでわざわざそんな面倒なことしなきゃならないんだ？","ENG":"Just leave it alone. Why do you keep bothering?","TWN":"亂就亂，就說不關你的事，幹嘛一直管我的頭髮？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L5_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"또, 또 그런다. 평소에도 좀 꾸미고 다니라니깐.","JPN":"はあ、これだから。普段もうちょっとおしゃれしたらいいのに。","ENG":"Seriously? Again? Why don't you groom yourself a little?","TWN":"你又來，就跟你說平時要多打扮。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L6_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"언니나 대장이나 노숙자 꼴로 돌아다니는데 무서워서 누가 도와 달라고 하겠어요?","JPN":"ユリさんも隊長もホームレスの姿で歩き回ってるし、誰も怖くて助けてくれって言えないと思いますよ。","ENG":"With you and Captain looking like hobos, who's gonna come to us asking for help?","TWN":"你和隊長弄得跟流浪漢一樣，人家看到就怕，誰還敢來跟你們求助啦？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L7_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"그런 요란한 꼴로 돌아다니면서 여태 안 잡혔던 네가 이상한 거지.","JPN":"そんな派手な格好で歩き回ってるのにまだ捕まってないそっちの方がおかしい。","ENG":"You're the weird one wearing those flashy clothes and still not getting caught all this time.","TWN":"你打扮得一副花枝招展的樣子在路上亂晃，到現在還沒被抓走我才覺得奇妙呢？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L8_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"잔소리 그만하고 라디오나 틀어.","JPN":"小言はもういいからラジオでも付けて。","ENG":"Stop your nagging and turn on the radio.","TWN":"懶得跟你吵，把收音機打開。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L10_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"손님 부탁이라면야. 듣고 싶은 채널 있어요?","JPN":"お客様のお望みとあれば。聞きたいチャンネルはありますか？","ENG":"If that's what the customer's wish. Which channel do you want?","TWN":"是，客人，你想聽哪個頻道？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"네 정신 사나운 수다만 아니면 아무거나 상관없어.","JPN":"うるさいおしゃべり以外なら何でもいい。","ENG":"Anything, as long as it drowns out your voice.","TWN":"什麼都好，只要不用再聽你嘮叨。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"언니 너무 야박하다~","JPN":"ユリさん、冷たい～","ENG":"Oof. That was harsh!","TWN":"姊姊，你很冷漠欸～"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"잠깐만 기다려?","JPN":"ちょっと待ってね。","ENG":"Just give me a sec.","TWN":"稍等一下喔？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MC_NPC_NULL_NULL","text":{"KOREA":"……에 대해, 경찰 관계자 분을 모시고 말씀을 들어 보도록 하겠습니다.","JPN":"……について、警察関係者をお招きしてお話を伺います。","ENG":"...we'll learn more after hearing from a police officer.","TWN":"……部分，我們請到警方相關人士蒞臨現場說明。"},"stage":{"bg":"SKYLINE_NIGHT2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L18_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"처음 뵙겠습니다. 제 4 특별기동수사대의 이유미 경정입니다.","JPN":"初めまして。第4特別機動捜査隊のカスカベ・ユミ警視です。","ENG":"Hello, nice to meet you. I'm Major Lee Yumi of SWAT 4.","TWN":"大家好，我是第四特遣機動隊的李悠美警正。"},"stage":{"bg":"SKYLINE_NIGHT2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MC_NPC_NULL_NULL","text":{"KOREA":"아직 어린 나이에도 훌륭하게 직무를 수행하신다던데요, 테라사이드 전역도……?","JPN":"まだお若いのに見事に職務を遂行されているということですが、テラサイドの戦域も……？","ENG":"We hear that you've already proven yourself plenty, despite your young age. Did you also participate in the Terraside battles?","TWN":"聽說你年紀輕輕，卻已經有不少的豐功偉業，像是特拉賽德戰役……？"},"stage":{"bg":"SKYLINE_NIGHT2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"저 외에도 많은 분들이 활약한 사건입니다.","JPN":"私以外にも多くの方々が活躍した事件です。","ENG":"It wasn't just me. There were many others on that case as well.","TWN":"那不是我一個人的功勞，是許多人一起的努力。"},"stage":{"bg":"SKYLINE_NIGHT2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"그리고 오늘 할 이야기는 특수능력이 사용된 강력 범죄에 대해서 아니었나요?","JPN":"ところで、今日の内容は特殊能力が使用された凶悪犯罪についてではなかったのですか？","ENG":"Also, wasn't today's topic about the violent crimes using special abilities?","TWN":"再說，今天的主題不是使用特殊能力的暴力犯罪嗎？"},"stage":{"bg":"SKYLINE_NIGHT2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MC_NPC_NULL_NULL","text":{"KOREA":"하하, 그, 그렇죠. 그러면 이 통계를 먼저…….","JPN":"はは、そ、そうですね。それではまずこの統計を……","ENG":"Ha ha. Y-yes, of course. Then let's take a look at the statistics here─","TWN":"哈哈，說的沒錯…那根據這份統計……"},"stage":{"bg":"SKYLINE_NIGHT2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"그 전에 먼저, 이 방송을 듣는 사람 중에 아직 죗값을 치르지 않은 범죄자가 있다면 지금 당장 경찰서로 가서 자수하세요.","JPN":"その前に、この番組を聞いている人の中でまだ罰を受けていない犯罪者がいるのなら、今すぐ自首してください。","ENG":"Before that, if there are any criminals listening to this broadcast who have not yet paid for their crimes, I suggest you all go turn yourselves in to the police right now.","TWN":"在這之前我想先呼籲，若是在收音機前尚有在逃的罪犯，請立刻到警察局自首。"},"stage":{"bg":"SKYLINE_NIGHT2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"카운터 범죄자들에게 관심이 쏠리면서 무능력자들은 자기가 저지른 짓이 별거 아니라고 합리화하더군요.","JPN":"カウンターによる犯罪が注目されることで、無能力者は自分たちのしたことが大したことではないと合理化しています。","ENG":"Incompetents appear to rationalize that their crimes are not crimes at all as attention shifts to Counter-related crimes.","TWN":"大家都只關注在制裁者犯罪的部分，卻將無能者犯罪的事合理化。"},"stage":{"bg":"SKYLINE_NIGHT2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"손에서 나오는 불로 사람을 죽이나 총으로 사람을 죽이나 마찬가진데 말이죠.","JPN":"手から出る火で人を殺すも、銃で人を殺すも同じことなのにです。","ENG":"However, killing another person is a serious crime. No matter if it's done by flames shot out of someone's hands, or by a gun.","TWN":"用手上的火殺人，與拿槍殺人無異，都是犯罪。"},"stage":{"bg":"SKYLINE_NIGHT2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MC_NPC_NULL_NULL","text":{"KOREA":"경정님, 자유 발언 시간을 드릴 테니까 지금은 대본대로 좀 부탁드립니다. 네?","JPN":"カスカベ警視、あとでコメントをお願いする時間を別途にもうけてありますので、今は台本どおりでお願いします。","ENG":"Major, I'll give you time to speak your mind afterwards, but could we please stick to the topic at hand right now?","TWN":"警正，等一下我們會給你自由發言的時間，現在可以先照流程走嗎？好嗎？"},"stage":{"bg":"SKYLINE_NIGHT2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":null,"text":{"KOREA":"……","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SKYLINE_NIGHT2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"꼭 우리 두고 하는 말 같네. 요즘 애들 무섭다, 정말.","JPN":"まるで私たちに言ってるみたい。最近の子って怖いなあ、もう。","ENG":"Sounds like she's talking right at us. Sheesh, kids these days are scary.","TWN":"好像是在對我們喊話欸，最近的人還真敢講。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L33_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"응? 표정이 왜 그래, 언니? 혹시 저 유미란 애랑 아는 사이?","JPN":"うん？　ユリさん、難しい顔してどうかしました？　もしかしてあのカスカベ警視って子と知り合い？","ENG":"Hmm? What's with the long face, Yuri? Do you know this Yumi kid?","TWN":"嗯？悠麗姊姊，你的表情是怎麼回事？你認識那個叫悠美的人嗎？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L34_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"……이전에 받은 의뢰 때문에 꼬리를 밟혀 본 적 있는 정도야.","JPN":"……昔受けた依頼のせいで尻尾をつかまれたことがあるくらいだ。  ","ENG":"...She used to follow me around because of the previous job we did.","TWN":"……之前執行委託時有栽在她手裡過而已。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"그보다 왜 하필 저런 골치 아픈 소리나 하는 채널을 틀고 그래?","JPN":"それより、なんでよりによってあのチャンネルに合わせたんだ？","ENG":"But why are you giving me a headache by turning on a channel like that?","TWN":"倒是你為何偏偏要轉到這個說出令人頭疼發言的頻道？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"어맛? 수다만 아니면 아무거나 상관없다더니?","JPN":"あらら？　おしゃべりじゃなかったら何でもいいって言いましたよね？","ENG":"Huh? Didn't you say anything was fine?","TWN":"拜託？是誰說只要不用聽我嘮叨什麼都好的？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"하여간 입만 살아선…….","JPN":"まったく、よく言うよ……","ENG":"Again with your sly tongue...","TWN":"就那張嘴厲害……"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L39_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"여기가 새로 개업한 이발소인가 보군. 염색도 해 주나?","JPN":"ここが新しく開業した床屋か。髪も染めてくれるのか？","ENG":"So this is the new barber shop, eh? Do you also dye hair here?","TWN":"這裡好像是新開的理髮院，有在幫人染髮嗎？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"아, 대장. 고생했어.","JPN":"あ、隊長。お疲れ。","ENG":"Hey, Captain. Good job out there.","TWN":"喔！是隊長，辛苦囉！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"이발소가 아니라 헤. 어. 살. 롱!","JPN":"床屋じゃなくてヘ・ア・サ・ロ・ンですよ！","ENG":"It's not a barber shop! It's a HAIR SALON!","TWN":"這裡不是理髮院，是美．髮．沙．龍！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"유리 언니에게 쓰려고 산 파란색 염색약은 남아 있는데, 저랑 머리색 맞추실래요?","JPN":"ユリさんに使おうと思って買ったブルーのヘアカラーは残ってるんですけど、私と髪の色一緒にします？","ENG":"There's also some blue hair dye leftover that I was gonna use on Yuri. Do you wanna get matching hair colors with me?","TWN":"我之前買來要給悠麗姊姊用的藍色染髮劑還有，你要和我染一樣的顏色嗎？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"됐다. 너희들 때문에 생긴 흰머리나 가릴 생각이었으니까.","JPN":"いや、いい。お前たちのせいで生えた白髪を隠そうと思っただけだからな。","ENG":"Nah. I was just thinking of covering up all the gray hairs you gave me.","TWN":"不必，我只是想遮一下被你們氣到長出來的白髮而已。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"어땠어, 의뢰인은?","JPN":"依頼人はどうだった？","ENG":"So? What did the client say?","TWN":"如何？委託人怎麼說？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"굉장히 고맙다고 전해 달라더군. 사례금도 따로 챙겨 줬다.","JPN":"とても感謝してるそうだ。謝礼も上乗せしてくれた。","ENG":"He told me to thank you both, and gave us a hefty reward too.","TWN":"他要我向大家表示謝意，另外還有準備一份報酬要給我們。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"그걸 받았다고? 자꾸 그러면 우리가 용병 놈들과 뭐가 달라?","JPN":"そんなの受け取ったのか？　それじゃあ傭兵のやつらと変わらないじゃないか。","ENG":"You received THAT as payment? Then what makes us any different from those mercs?","TWN":"你收下了嗎？這樣我們和那些傭兵有何不同？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"본전치기도 못할 헐값에 목숨 걸고 움직이는 미치광이들이란 점이.","JPN":"元も取れないような安い賃金に命がけで動く狂人、っていうところがな。","ENG":"The fact that we're lunatics who risk their lives for chump change.","TWN":"我們每天這樣拚死拚活的，卻連本錢都賺不回來，"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"설마 네가 혼자 움직일 동안 썼던 돈이 땅에서 솟아난 거라고 생각하진 않았겠지?","JPN":"まさかお前が単独行動中に使った金が地から沸いてくるとでも思ってないよな？","ENG":"Or did you really believe that the money you spent just magically grew on trees?","TWN":"你應該不會以為，錢會在你行動時自己從地上長出來吧？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"체면 차리는 것도 실속이 있을 때야. 이걸로 당분간 맨손으로 싸울 걱정은 덜었어.","JPN":"格好つけられるのも余裕があるときだけだぞ。これで当分素手で戦う心配はなくなった。","ENG":"We only save face when we can. At least with this, we won't be fighting bare-handed for the time being.","TWN":"面子要顧肚子也要顧好嗎？只要有這些錢，我們就暫時不需要擔心作戰時會手無寸鐵。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"칫…….","JPN":"ちっ……","ENG":"Tch...","TWN":"嘖……"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L6_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"예에~! 만세~! 마음껏 사냥해 버리자~!","JPN":"イェーイ！　ばんざ～い！　思いっきり狩っちゃお～！","ENG":"Yay! Hurray! Let's keep hunting!","TWN":"呀呵～！萬歲～！可以盡情狩獵囉～！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L7_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"조용히 해, 레비아. 헛소리하다 괜히 지나가던 주민들에게 신고당해.","JPN":"静かにしろ、レヴィア。変なこと言うと通りすがりの住人に通報される。","ENG":"Quiet, you! Keep up with that nonsense and the townsfolk here will report us to the police.","TWN":"你小聲點，莉維亞。你這樣亂說話，到時候被路過的居民舉發。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"언니는 대장한테 맘 상해 놓고 꼭 나한테 그런다? 알쓰요오~","JPN":"ユリさんたら隊長に怒られるときまって私にあたりますね。わかりましたよ～","ENG":"You always scold me after getting in trouble with the Captain, you know? Okaaaay!","TWN":"姊姊，因為隊長嗆你，你就拿我出氣嗎？哭哭～"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"유리 말이 맞긴 하지. 이 대낮에 출근 안 하고 빈둥거리는 사람이 우리 말고 있다면 말이야.","JPN":"カスカベの言うことも間違いではないさ。こんな真昼に会社にも行かず遊んでるやつが俺たち以外にもいるならな。","ENG":"Yuri's right, though. But only if we're not the only ones who don't go to work in the morning.","TWN":"悠麗說的沒錯，大白天不上班在街上閒晃的人可不只有我們。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"그리고 조금 이르지만…… 다음 의뢰가 들어왔다.","JPN":"それから、ちょっと早いが……次の依頼が入った。","ENG":"Also, I know it's a little early, but... We have another job.","TWN":"另外，雖然時間有點早……不過又有下一個委託。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"또? 부르는 곳이 갈수록 많아지네.","JPN":"また？　依頼が増える一方だな。","ENG":"Another one? Looks like we're getting popular.","TWN":"又來？委託還真是越來越多呢。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"카운터가 늘어날수록 장래 유망한 서비스 업종이지. 내가 말 안 했던가?","JPN":"カウンターが多くなれば多くなるほど将来有望なサービス業だ。そう言っただろう？","ENG":"Didn't I tell you this would become a more lucrative business as the number of Counters increases?","TWN":"誰叫我們這一行就是制裁者越多，業績越好呢？我沒說過嗎？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"하지만 두 사람 다 긴장해야 할 거야. 이번 타깃은 거물이다.","JPN":"だが二人とも緊張した方がいいぞ。今度のターゲットは大物だ。","ENG":"However, I'll need both of you to stay on your toes. The target's a big one this time.","TWN":"不過你們二個人都要繃緊神經，這次的目標可是個大人物。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"누군데 그렇게 뜸을 들여요? 포스트 성냥팔이라도 나타났대요?","JPN":"もったいぶって、どんな大物なんですか？　次世代のマッチ売りでも現れたんですか？","ENG":"Well, tell us then! Has another Matchmaker-like gang appeared?","TWN":"是誰啊？那麼神祕。難道是賣火柴組織的嗎？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L18_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"슈~퍼 성냥팔이라거나?","JPN":"す～ぱ～マッチ売りとか？","ENG":"Like a SUPER Matchmaker?","TWN":"還是超～級賣火柴組織？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L19_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"그런 낯 뜨거운 별명을 달고 다닐 만큼 뻔뻔한 놈이 있으면 그거대로 무섭겠군.","JPN":"そんな恥ずかしい名で活動するほど図々しいやつがいたら、それはそれで怖いな。","ENG":"It would be terrifying if someone actually did use a stupid name like that.","TWN":"會取這種羞恥的外號的話，那確實還蠻嚇人的。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"하지만 이번에는 어쩌면…… 성냥팔이와 다른 의미로 위험한 상대다.","JPN":"だが今回の相手は……マッチ売りとは別の意味で危険かもしれない。","ENG":"This time... the target's dangerous in a different way.","TWN":"不過這次目標的危險程度……和賣火柴的不太一樣。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"이 여자에요? 타깃이라는 게?","JPN":"ターゲットって、この女ですか？","ENG":"This woman? She's the target?","TWN":"目標就是這個女人嗎？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"얼굴만 봐서는 잘 모르겠는데…….","JPN":"顔だけではよくわからないけど……","ENG":"I don't think she looks all that dangerous...","TWN":"臉看不太出來……"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"이름은 베로니카. 맨션이란 암살 조직에서 활동했던 암살자라더군.","JPN":"名前はベロニカ。マンションという暗殺組織で活動していた暗殺者らしい。","ENG":"Her name is Veronica. She's an assassin working for a group called Mansion.","TWN":"她叫貝洛妮卡，先前曾經是曼森暗殺組織的殺手。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"암살자? 이런 순한 얼굴로?","JPN":"暗殺者？　こんな大人しそうな顔で？","ENG":"An assassin? With an innocent face like that?","TWN":"殺手？她看起來一副天真無邪欸？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"얼굴에 속았다간 큰코 다칠 거다. 몇 명이나 죽였을지 감도 안 잡힐 정도니까.","JPN":"外見に騙されるとひどい目に合うぞ。何人殺したか計り知れないほどだからな。","ENG":"Don't be fooled by her appearance. Her body count is unimaginable.","TWN":"人不可貌相，她身上不知道揹幾條人命呢。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"조사해 보니 뒷세계에는 악명이 자자했던 모양이야.","JPN":"調査してみたが、裏世界ではかなりの凄腕だったらしい。","ENG":"I did some digging around, and she's notorious in the underworld.","TWN":"我有稍微調查一下，她在地下世界似乎惡名昭彰。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"달리는 스포츠카에 탄 표적을 포크 하나로 저격했다는 소문도 나돌 정도니까.","JPN":"走行中のスポーツカーに乗っている標的をフォーク一つで狙撃したという噂もあるくらいだ。","ENG":"There's even a rumor that she sniped a target in a moving sports car with a fork.","TWN":"還有聽說她曾經用一個叉子，就成功狙擊在賽車裡的目標呢。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"어차피 <color=#ffd34c>그런</color> 능력을 가진 카운터겠지. 하여튼 범죄자 놈들 허풍은 알아 줘야 돼.","JPN":"どうせ<color=#ffd34c>そういう</color>能力を持ってるカウンターなんだろ。まったく、犯罪者どものはったりときたら。","ENG":"I bet she's just <color=#ffd34c>one of those</color> Counters. But you gotta give it up for criminals and their bragging.","TWN":"她應該就是有<color=#ffd34c>那種</color>能力的制裁者吧？那些罪犯老愛誇大其辭。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"카운터가 아니야.","JPN":"カウンターではない。","ENG":"She's not a Counter.","TWN":"她不是制裁者。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_DOOR_CAR"},{"id":"L36_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"뭐?","JPN":"は？","ENG":"What...?","TWN":"什麼？"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L37_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"그럼 퓨처 앳 워가 만든 살인 병기라도 돼요?","JPN":"じゃあ、フューチャーアットウォーが作った殺人兵器か何かですか？","ENG":"Then she's an assassin android made by Future-at-War?","TWN":"還是她是天啟兵器打造的殺人武器？"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L39_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"아니. 우리처럼 손에서 불도 광선도 쏘지 못하는 보통 사람이라더군.","JPN":"いや。俺たちのように手から火も光線も出せない普通の人間らしい。","ENG":"No, she's just another normal person who can't shoot flames and beam out of her hands.","TWN":"不，她和我們一樣是普通人，手上不會有火焰，也不會有閃光。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"그리고 이거, 포크로 죽였다는 사건의 보고서다.","JPN":"それからこれ、フォークで殺したという事件の報告書だ。","ENG":"And here. This is the report on the fork assassination case.","TWN":"還有這個，這是叉子殺人事件的報告。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"부검의 소견도 달려 있네. 진짠가 봐, 유리 언니.","JPN":"解剖医の所見もついてる。本当みたいですね、ユリさん。","ENG":"There's even an autopsy report. Looks like it really did happen, Yuri.","TWN":"悠麗姊姊，上面還有法醫的說明，應該是真的。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L44_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"아무리 훈련 받았다고 해도 그렇지……. 보통 사람이 이런 짓까지 가능해?","JPN":"いくら訓練されたとしても……普通の人間がこんなことまでできる？","ENG":"Even if she's a trained assassin... How's that even possible for a normal human being?","TWN":"就算她曾經受過多少訓練……但一個普通人有辦法做到這種程度嗎？"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"잘 모르겠군. 포크를 살인에 써야 할 만큼 절박한 상황은 아직까지 없어서.","JPN":"さあな。フォークを殺人に使わなくてはいけないくらい切迫した状況は今までなかったんでな。","ENG":"Who knows. I've never been in a position desperate enough to use a fork as a murder weapon before.","TWN":"不知道，畢竟我也沒被逼到需要用叉子殺人的經驗。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"보통은 그냥 저격총을 쏘겠죠. 이런 건 자기 사냥 솜씨를 과시하는 퍼포먼스라구요.","JPN":"普通は銃を使いますよね？　これは自分の狩りの腕を見せびらかすパフォーマンスですよ。","ENG":"Normally, you would just use a sniper rifle. But this one... It looks like she was showing off.","TWN":"通常都是用狙擊槍吧？她根本是在炫技吧？"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"사람 목숨을 가지고 과시한단 말이지…….","JPN":"人の命で腕を見せびらかす、ねえ……","ENG":"Showing off by killing another person...","TWN":"拿人命來當作炫技的工具嗎……"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"대장, 이 여자 지금 어디 있는지는 알아?","JPN":"隊長、この女が今どこにいるかわかる？","ENG":"Captain, do you know where she is right now?","TWN":"隊長，你知道她現在在哪裡嗎？"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"희생자의 유가족에게서 첩보가 들어왔다. 인상착의도 그 사람이 보내 준 거야.","JPN":"犠牲者の遺族から情報提供があった。人相書きもそこから送られてきたものだ。","ENG":"We got a tip from the victim's family. That photo was provided by them.","TWN":"受害者家屬有提供情報，穿著和長相也是家屬提供的。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"맨션이 무너진 뒤 체포됐는데, 사법 거래로 신분을 숨기고 파견업에 종사 중이더군.","JPN":"マンションの崩壊後に逮捕されたんだが、司法取引で身分を隠して派遣業に従事しているらしい。","ENG":"She was arrested when Mansion collapsed, but after a plea bargain, she is currently working in the temporary personnel services under a new identity.","TWN":"她在曼森組織垮台後遭到逮捕，現在因為司法交易而隱姓埋名從事派遣業。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"그 정보 준 사람, 믿을 만은 해?","JPN":"その情報元、信頼できるのか？","ENG":"Are you sure we can trust the person who gave us the info?","TWN":"提供情報的人可信嗎？"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L8_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"일단은. 내가 조사할 수 있는 선에서는 전부 확인해 봤다.","JPN":"一応はな。俺が調べられるところまでは全部確認してみた。","ENG":"For now. It all checked out when I looked into it myself.","TWN":"應該吧，我已經在可調查的範圍內確認過。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L9_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"……알겠어. 언제 시작할 거야?","JPN":"……わかった。いつ始める？","ENG":"...All right. So when do we start?","TWN":"……好吧，什麼時候開始？"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"네 머리 다 자르는 대로.","JPN":"お前のヘアカットが終わり次第。","ENG":"Right after you get a haircut.","TWN":"等你剪完頭髮後。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"장비는 내가 챙겨 두지. 제대로 깔끔하게 자르고 와.","JPN":"装備は俺が準備しておく。ちゃんと髪切って来い。","ENG":"I'll start packing. Make sure to cut it nicely, okay?","TWN":"裝備就交給我吧，你剪完頭髮再來找我。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"}]`);export{e as default};